return {
    ["Name"] = script.Name,
    ["Date"] = "September 26, 2025",
    ["Title"] = "UPDATE 15 \240\159\155\161",
    ["Image"] = "rbxassetid://108294156233914",
    ["Code"] = "patchnotes_season1",
    ["Changes"] = {
        { "Title", "\240\159\141\130 SEASON 1" },
        { "Description", "Welcome to Season 1 \226\128\148 The Warp Season!" },
        { "Description", "This is the first ever season reset! That means there\'s a brand new Ranked season, the first ever set of Ranked rewards, & the introduction of the first ever Season Pass!" },
        { "Description", "Not only that, but there\'s a brand new map, new rewards, and much, much more!" },
        { "Description", "Check out all of the brand new \"Warp\" themed content below!" },
        { "Thumbnail", "rbxassetid://76121468587359", "The brand new Sensei & Co. room" },
        { "Title", "\240\159\148\171 WEAPONS" },
        { "Description", "We\'ve had \"Standard\" weapons & we\'ve also had \"Prime\" weapons. Now introducing.. \"Contraband\" weapons!" },
        { "Description", "Contraband weapons are ultra rare, ultra special weapons that are just that much cooler than Prime weapons. The top of the top weapons in the world." },
        { "Description", "The first set of Contraband weapons are now available in the brand new Season Pass!" },
        { "Description", "Distortion \226\128\148 The brand new, Contraband primary weapon that\'s able to consume nearby players with a gravitational vortex! Available in the Season Pass!" },
        { "Thumbnail", "rbxassetid://116781152837212", "The brand new Contraband primary weapon \"Distortion\"" },
        { "Description", "Warper \226\128\148 The brand new, Contraband secondary weapon that\'s able to open portals and warp players between any distance instantly! Available in the Season 1 Bundle!" },
        { "Thumbnail", "rbxassetid://73681341018446", "The brand new Contraband secondary weapon \"Warper\"" },
        { "Description", "Warpstone \226\128\148 The brand new, Prime utility weapon that can be thrown to instantly warp to a desired location! Available for FREE in the Season Pass!" },
        { "Thumbnail", "rbxassetid://112410107324359", "The brand new Prime utility weapon \"Warpstone\"" },
        { "Description", "While most Season Pass rewards are only available to earn for a limited time during the season, we believe that weapons should always be obtainable regardless of when you start playing the game (RIVALS). These weapons will permanently go onsale for a fair amount of keys after this season is over!" },
        { "Description", "Check out the Season Pass now!" },
        { "Title", "\240\159\155\161 SEASON PASS" },
        { "Description", "The first ever Season Pass is here!" },
        { "Description", "Earn FREE keys, charms, wraps, finishers, emotes, skins, and even a weapon just by playing the game!" },
        { "Thumbnail", "rbxassetid://133993700895900", "The first ever Season Pass" },
        { "Description", "Every time your Season Pass levels up, you get a free reward! Level it up by gaining Pass XP!" },
        { "Description", "Pass XP can be earned simply by winning rounds in any kind of duel OR by simply playing the game! You can level up your Season Pass 7 times per week!" },
        { "Thumbnail", "rbxassetid://118301626429590", "This is how you level up your Season Pass" },
        { "Description", "Want access to even more rewards? The best kind of loot? Maybe even a Contraband weapon, free skin cases, & even more of everything else? Check out the Prime Season Pass upgrade!" },
        { "Description", "Check out the Season 1 Bundle to get an insane value deal that includes the Prime Season Pass upgrade, a brand new Contraband weapon, an exclusive skin, and much more!" },
        { "Thumbnail", "rbxassetid://114061464570835", "Look at all the cool stuff in the Season 1 Bundle" },
        { "Description", "The Season Pass can be found by pressing the \"Pass\" button at the bottom of your screen in the lobby. All rewards, offers, and relevant bundles can be found in the Season Pass page!" },
        { "Title", "\240\159\143\134 RANKED SEASON" },
        { "Description", "Season 0 has ended! All ranked players that participated in this experimental season have received the new Season 0 charm and a bunch of Glory!" },
        { "Description", "The top 200 Archnemesis players worldwide from last season have also been given the brand new, exclusive, Mythical Arch Katana skin! Congratulations!" },
        { "Thumbnail", "rbxassetid://86754678822547", "A look at the \"Season 0\" charm and the top 200 reward \"Arch Katana\"" },
        { "Description", "Glory is the brand new currency given out to all ranked players. You get more Glory based on your final ELO in the season & your total Ranked wins! Spend your Glory in the brand new Ranked Shop!" },
        { "Description", "For transparency purposes, this is the exact Glory Payout formula:" },
        { "Description2", "1,250 \195\151 RANKED_WINS / 250 + 1,250 \195\151 FINAL_ELO / 3,600" },
        { "Description2", "In the formula, RANKED_WINS and FINAL_ELO have a limit of 250 and 3,600 respectively" },
        { "Thumbnail", "rbxassetid://104883063044519", "The new Ranked currency, \"Glory\"" },
        { "Description", "Now that there\'s a new season, that means there\'s new free rewards to grind for! The Phoenix Rifle has been discontinued and replaced with the brand new Ranked Contract!" },
        { "Description", "You can now earn Glory, exclusive charms, wraps, finishers, & finally a brand new free skin from the new Ranked Contract feature! You can find the Ranked Contract in the Ranked page after you finish placements!" },
        { "Thumbnail", "rbxassetid://85692311137157", "The brand new Ranked Contract rewards" },
        { "Description", "Last but not least, you should expect to see much fairer matchups in Ranked moving forward. Players in the top ranks will experience slightly longer matchmaking times to ensure they get quality duels and to prevent them from stomping lower ranked players." },
        { "Description", "However, our matchmaker may still make mistakes once in a blue moon. Rest assured that the ELO gains/losses will compensate for this. If you are matched up against players much higher of a rank than you, you will either gain more or lose less ELO than usual." },
        { "Title", "\240\159\143\133 RANKED SHOP" },
        { "Description", "The first ever Ranked Shop is here!" },
        { "Description", "Spend the hard-earned Glory from Ranked right here in the Ranked Shop!" },
        { "Description", "The Ranked Shop contains charms, wraps, finishers, emotes, & even skins that can all be earned for FREE just by playing Ranked!" },
        { "Description", "The Glorious weapon skins can be purchased once all Glorious cosmetics have been purchased in order! Check out the Ranked Shop to learn more!" },
        { "Thumbnail", "rbxassetid://82385276747900", "Spend your Glory in the new Ranked Shop" },
        { "Title", "\240\159\155\146 SHOP" },
        { "Description", "The Shop\'s home page has been revamped! Loose shop items have been seperated into two sections by the Season Pass card!" },
        { "Description", "The brand new Ranked Shop is here! Click on the \"Ranked\" tab to see more, only available to players that have Ranked unlocked!" },
        { "Description", "The Gifting, Weapons, & Codes buttons have moved! Click on the \"More\" tab in the Shop to see them!" },
        { "Thumbnail", "rbxassetid://108673755455714", "The new Home page in the Shop" },
        { "Description", "The Shadow Ink wrap has been replaced by the new Hologram Arena wrap!" },
        { "Description", "The Triplaser wrap has been replaced by the new Honey wrap!" },
        { "Thumbnail", "rbxassetid://94639458730831", "\"Honey\" on the left, \"Hologram Arena\" on the right" },
        { "Description", "Psst.. you can now also buy Skin Cases for FREE. Collect enough Skin Tickets from the Season Pass and you\'ll be able to buy a Skin Case of your choice!" },
        { "Description", "Not allowed to purchase lootboxes? No worries! Skins in the Daily Shop are now onsale for Skin Tickets, too! However, refreshing your Daily Shop will disable this for the rest of the day." },
        { "Thumbnail", "rbxassetid://98147542132491", "Purchase skins for FREE using the new Skin Tickets" },
        { "Title", "\240\159\148\174 DIMENSION" },
        { "Description", "A brand new, permanent map is here \226\128\148 Dimension!" },
        { "Description", "A realm where all realities converge. Two distant childhood memories of company leaders blur into one \226\128\148 drifting through the void and ripping through all planes of existence." },
        { "Description", "Made by @GreatGuyBoom!" },
        { "Thumbnail", "rbxassetid://72743815851430", "The brand new permanent map, \"Dimension\"" },
        { "Title", "\240\159\142\174 GAMEPLAY" },
        { "Description", "Projectile weapons, such as Bow or Daggers, should feel much more responsive and consistent" },
        { "Description", "You can now challenge someone to a 1v1 from the Party page" },
        { "Description", "Destructable objects in maps, such as explosive barrels & windows, now respawn every round!" },
        { "Description", "Removed an out-of-bounds area in the Station map" },
        { "Description", "Added a ledge on both sides of the Construction map that used to only be on one side" },
        { "Description", "Removed an invisible wall above a ramp in the Battleground map" },
        { "Description", "You no longer lose points from melee eliminations in Gun Game!" },
        { "Description", "You no longer have reduced health when you\'re on the final weapon in Gun Game!" },
        { "Description", "The final weapon in Gun Game, the Glast Shard, now allows you to double jump!" },
        { "Description", "Shorty, Katana, Knife, & Trowel have been removed from Gun Game!" },
        { "Title", "\240\159\148\171 BALANCE CHANGES" },
        {
